sp_widget.client_script:
api.controller=function() {
  /* widget controller */
  var c = this;

  c.userInput = '';
  c.submitter = '';
  c.isSubmitting = false;
  c.errorMessage = '';

  c.$onInit = function() {
    c.loadCurrentUser();
  };

  c.loadCurrentUser = function() {
    c.server.get({
      action: 'getCurrentUser'
    }).then(function(response) {
      c.submitter = response.data.submitter || '';
    });
  };

  c.submitPrompt = function() {
    if (!c.userInput || c.userInput.trim() === '') {
      c.errorMessage = 'Please enter your prompt text.';
      return;
    }

    c.isSubmitting = true;
    c.errorMessage = '';

    c.server.post({
      action: 'createPrompt',
      userInput: c.userInput.trim()
    }).then(function(response) {
      if (response.data.success) {
        // Redirect to the list page
        $location.url('/sp/?id=promptception_list');
      } else {
        c.errorMessage = response.data.error || 'An error occurred while creating the prompt.';
        c.isSubmitting = false;
      }
    }).catch(function(error) {
      c.errorMessage = 'An error occurred while creating the prompt.';
      c.isSubmitting = false;
    });
  };

  c.clearError = function() {
    c.errorMessage = '';
  };
};

sp_widget.css:
.prompt-input-container {
  max-width: 600px;
  margin: 0 auto;
  padding: 20px;
}

.prompt-form {
  background: #fff;
  border: 1px solid #e1e8ed;
  border-radius: 8px;
  padding: 24px;
  box-shadow: 0 2px 8px rgba(0,0,0,0.1);
}

.form-header {
  margin-bottom: 24px;
  text-align: center;
}

.form-title {
  font-size: 24px;
  font-weight: 600;
  color: #2c5aa0;
  margin-bottom: 8px;
}

.form-subtitle {
  color: #666;
  font-size: 14px;
}

.form-group {
  margin-bottom: 20px;
}

.form-label {
  display: block;
  margin-bottom: 8px;
  font-weight: 500;
  color: #333;
}

.form-input {
  width: 100%;
  padding: 12px;
  border: 2px solid #e1e8ed;
  border-radius: 6px;
  font-size: 16px;
  transition: border-color 0.2s;
  box-sizing: border-box;
}

.form-input:focus {
  outline: none;
  border-color: #2c5aa0;
}

.form-input.readonly {
  background-color: #f8f9fa;
  color: #666;
  cursor: not-allowed;
}

.submitter-display {
  background: #f8f9fa;
  padding: 12px;
  border-radius: 6px;
  border: 1px solid #e1e8ed;
  color: #666;
  font-size: 14px;
}

.submit-button {
  background: #2c5aa0;
  color: white;
  border: none;
  padding: 12px 24px;
  border-radius: 6px;
  font-size: 16px;
  font-weight: 500;
  cursor: pointer;
  transition: background-color 0.2s;
  width: 100%;
}

.submit-button:hover:not(:disabled) {
  background: #1e3f6b;
}

.submit-button:disabled {
  background: #ccc;
  cursor: not-allowed;
}

.error-message {
  background: #fee;
  color: #c53030;
  padding: 12px;
  border-radius: 6px;
  border: 1px solid #feb2b2;
  margin-bottom: 20px;
  font-size: 14px;
}

.error-message .fa {
  margin-right: 8px;
}

.character-count {
  text-align: right;
  font-size: 12px;
  color: #999;
  margin-top: 4px;
}

.character-count.near-limit {
  color: #f39c12;
}

.character-count.at-limit {
  color: #e74c3c;
}

sp_widget.script:
(function() {
  /* populate the 'data' object */
  /* e.g., data.table = $sp.getValue('table'); */

  if (input && input.action === 'getCurrentUser') {
    // Get current user information
    var currentUser = gs.getUser();
    data.submitter = currentUser.getDisplayName();
  }

  if (input && input.action === 'createPrompt') {
    try {
      // Validate input
      if (!input.userInput || input.userInput.trim() === '') {
        data.success = false;
        data.error = 'User input is required.';
        return;
      }

      // Create new prompt record
      var gr = new GlideRecord('x_885412_promptc_0_prompt');
      gr.initialize();
      gr.setValue('user_input', input.userInput.trim());
      gr.setValue('submitter', gs.getUserID()); // Set current user's sys_id
      gr.setValue('display_on_portal', true);
      gr.setValue('state', 'new');

      var promptId = gr.insert();

      if (promptId) {
        data.success = true;
        data.promptId = promptId;
      } else {
        data.success = false;
        data.error = 'Failed to create prompt record.';
      }

    } catch (e) {
      gs.error('Error creating prompt: ' + e.message);
      data.success = false;
      data.error = 'An error occurred while creating the prompt.';
    }
  }
})();
